@ARTICLE{10.1186/s12951-025-03967-x,
	author = {Huang M and Liu Y and Xiao T and Qi P and Shen W and Huo Y and Fu B and Hao J and Ao Q and Huo Y and Cai G and Chen X and Hong Q and Wu M and Feng Z},
	title = {Charge-dependent mitochondrial targeting of cerium-doped polypyrrole nanoparticles to injured renal tubules for acute kidney injury therapy.},
	journal = {J Nanobiotechnology},
	year = {2025},
	abstract = {Acute kidney injury (AKI) is a critical medical condition with limited treatment options and frequently progresses to chronic kidney disease (CKD). This study introduces a novel nanotherapeutic approach based on positively charged cerium-doped polypyrrole nanoparticles [(+)CePPy] for AKI treatment. The positive surface charge of these nanoparticles enhances their cellular uptake and mitochondrial targeting in proximal tubular epithelial cells (PTECs), which play a central role in the pathophysiology of AKI. Comprehensive in vitro and in vivo evaluations demonstrate that (+)CePPy effectively scavenges reactive oxygen species (ROS), ameliorates mitochondrial dysfunction, attenuates apoptosis, and prevents AKI-to-CKD progression. The nanoparticles exhibit excellent biocompatibility and undergo efficient renal clearance within 14 days. Mechanistically, the renoprotective effects involve both direct elimination of ROS and the reinforcement of endogenous antioxidant defenses through upregulation of the Mpv17 mitochondrial membrane protein-like (Mpv17l) pathway. Furthermore, we report that early endosome antigen 1 (EEA1) upregulation mediates the enhanced renal targeting of (+)CePPy under AKI conditions. This research highlights the potential of charge-modulated nanotherapeutics as a translatable strategy for renal protection and presents a promising approach for AKI treatment. GRAPHICAL ABSTRACT: [Image: see text] SUPPLEMENTARY INFORMATION: The online version contains supplementary material available at 10.1186/s12951-025-03967-x.},
	doi = {10.1186/s12951-025-03967-x},
	pmid = {41449392},
	note = {PMC12853839}
}

@ARTICLE{10.1002/advs.202512278,
	author = {Xu Y and Wang Y and Jiang S and Li Y and Li G and Liu Y and Li S and Zhou Y and Liu Q and Zhou Y and Chen W and Li H and Mao H},
	title = {Tubule-Derived IFN-α Promotes GSDMD-Mediated Macrophage Pyroptosis to Drive Renal Inflammation and Fibrosis Through JAK2/STAT2 Activation.},
	journal = {Adv Sci (Weinh)},
	year = {2026},
	abstract = {Macrophages exhibit high plasticity in response to tubular epithelial cell (TEC) injury. Gasdermin D (GSDMD)-mediated pyroptosis amplifies the inflammatory and fibrogenic cascade, yet its role in chronic kidney disease (CKD) remains elusive. Herein, GSDMD is upregulated in kidney macrophages following unilateral renal ischemia-reperfusion injury (UIRI) or folic acid-induced injury, paralleling elevated pyroptosis rates. Clinically, the active fragment GSDMD-N localizes primarily to CD68+ macrophages, and its renal level positively correlates with fibrosis severity across diverse CKD etiologies, reinforcing its pathogenic relevance. Macrophage-specific deletion of Gsdmd ameliorates pyroptosis, inflammation, and renal fibrosis in both murine models, without affecting acute tubular damage in bilateral IRI. Mechanistically, injured TECs initiate this cascade through secreted IFN-α, which activates the IFNAR1/JAK2/STAT2 axis in macrophages​. STAT2 then forms a complex with IRF9, directly binding to the Gsdmd promoter to transcriptionally upregulate GSDMD expression. Genetic ablation of Jak2, Stat2, or Ifnar1 reduces GSDMD and GSDMD-N levels and inhibits IL-1β/IL-18 secretion. Notably, administration of an IFN-α neutralizing antibody attenuates UIRI-induced pyroptotic macrophage, inflammation, and renal fibrosis. Collectively, the findings uncover a STAT2/IRF9-dependent paracrine IFN-α feedback loop that orchestrates GSDMD-mediated pyroptosis, linking injured TECs to macrophage-driven renal inflammation and fibrosis. Targeting this axis represents a promising strategy to halt CKD progression.},
	doi = {10.1002/advs.202512278},
	pmid = {41387110 [Indexed for MEDLINE]},
	note = {PMC12931230}
}

@ARTICLE{10.7150/thno.112905,
	author = {Xie M and Fu X and Lan Y and Zhang Y and Li H and Su Y and Zhou K and Zhang Y and Ding X and He J and Mao Z},
	title = {Spatially selective clearance of inflammation-mediated reactive oxygen species in injured kidney cells.},
	abstract = {Rationale: Kidney injury is characterized by the accumulation of reactive oxygen species (ROS). Current ROS scavengers utilized in the treatment of clinical kidney injury lack the capacity for spatially selective ROS scavenging within the injured cells, often resulting in irreversible damage to healthy tissues. Methods: We developed a spatially selective therapeutic strategy using platelet-shipped tetrahedral framework nucleic acids (TFNAs@PLT). Results: In this system, platelets achieve spatial targeting of injured kidney cells by responding to inflammatory signals and releasing TFNAs following TNF-α activation. TFNAs subsequently exert a potent antioxidant effect in the injured cells. We have demonstrated that TFNAs@PLT reduces pyroptosis and apoptosis through the Caspase-3/GSDME pathway and the NLRP3-mediated Caspase-1/IL-1β pathway in the acute kidney injury (AKI) mouse model, while also inhibiting renal fibrosis via the NLRP3/Caspase-1 and the TNF-α/NF-κB pathways in the chronic kidney disease (CKD) mouse model. Conclusion: TFNAs@PLT offers a safe and effective therapeutic strategy for kidney injury and other inflammation-mediated diseases.},
	doi = {10.7150/thno.112905},
	pmid = {41355960 [Indexed for MEDLINE]},
	note = {PMC12679581}
}

@ARTICLE{10.7150/thno.120560,
	author = {Lee S and Suh SH and Ma SK and Kim J and Park S and Kim SW and Lee JY},
	title = {ROS-responsive graphene-hyaluronic acid nanomedicine for targeted therapy in renal ischemia/reperfusion injury.},
	abstract = {Background: Acute kidney injury (AKI) frequently progresses to chronic kidney disease (CKD) through the AKI-to-CKD transition; however, effective treatment strategies remain challenging due to the complex and multifactorial pathophysiology of this process. This study aims to develop a multifunctional nanoplatform for kidney-specific targeting, reactive oxygen species (ROS) scavenging, and anti-fibrotic drug delivery to mitigate AKI-to-CKD progression. Methods: Reduced graphene oxide (rGO) was conjugated with hyaluronic acid (HA) to form HA/rGO nanoparticles, enabling CD44-mediated renal targeting and ROS-responsive drug release. Paricalcitol, a hydrophobic anti-fibrotic agent, was loaded onto HA/rGO to form P/HA/rGO. The physicochemical characteristics, ROS-scavenging capacity, and oxidative stress-responsive drug release were evaluated. In vitro cytoprotection was assessed using HK-2 cells under oxidative stress. In vivo studies using ischemia/reperfusion (IR) injury mouse models assessed biodistribution, renal targeting, and therapeutic efficacy after systemic administration of P/HA/rGO. Results: HA/rGO nanoparticles demonstrated potent antioxidant activity and significantly protected HK-2 cells from ROS-induced cytotoxicity. P/HA/rGO exhibited a high paricalcitol loading efficiency (93%) and released 26% of the drug over 30 days under oxidative conditions. P/HA/rGO selectively accumulated in IR-injured kidneys via HA-CD44 interactions, decreased serum NGAL and cystatin C levels, and effectively attenuated tubular injury, fibrosis, inflammation, and apoptosis compared to vehicle-treated controls. Conclusion: The P/HA/rGO nanoplatform enables kidney-targeted delivery of paricalcitol with ROS-scavenging and ROS-responsive release properties, providing a promising therapeutic strategy to suppress the AKI-to-CKD transition via integrated targeting and microenvironment-responsive therapy.},
	doi = {10.7150/thno.120560},
	pmid = {41346711 [Indexed for MEDLINE]},
	note = {PMC12674889}
}

@ARTICLE{10.1038/s41419-025-08268-7,
	author = {Gao P and Cenatus S and Henley N and Pichette V and Mallette FA and Barrera-Chimal J and Gerarduzzi C},
	title = {Inhibition of MCL-1 to eliminate senescent cells and mitigate renal fibrosis in aristolochic acid nephropathy.},
	journal = {Cell Death Dis},
	year = {2025},
	abstract = {The role of tubular epithelial cells (TEC) senescence in the progression from acute kidney injury (AKI) to chronic kidney disease (CKD) remains debated due to the complexity of senescent cell populations and their pro-survival mechanisms. To directly assess the contribution of TEC senescence to AKI-to-CKD progression, we employed an aristolochic acid nephropathy (AAN) mouse model. Here, we demonstrated that AAI-induced DNA damage specifically drives TEC senescence during AKI-to-CKD progression. Concomitant with the emergence of senescence, immunofluorescence staining revealed the expression of anti-apoptotic proteins, including BCL-2, BCL-xL, and MCL-1, within KIM1+ tubules-a marker of tubular injury. To further characterize these senescent cells, we integrated this model with snRNA-Seq data and identified a distinct population of KIM1+ senescent TEC exhibiting resistance to apoptosis through upregulation of pro-survival proteins such as MCL-1, BCL-2, and BCL-xL. To evaluate the therapeutic potential of targeting these pathways, we treated AAN mice with the MCL-1-specific inhibitor UMI-77 and the senolytic ABT-263 (targeting BCL-2/BCL-xL) during both the acute and late phases. Interestingly, only UMI-77 administration during the acute phase effectively reduced tubular senescence and mitigated fibrosis. In contrast, late-phase treatment had only marginal benefits. Notably, ABT-263 failed to eliminate senescent cells and instead exacerbated fibrosis, suggesting that while senescent TEC relies on pro-survival mechanisms to evade apoptosis, their dependency on specific anti-apoptotic proteins varies. Our study provides a high-resolution molecular framework for understanding TEC senescence and identifies MCL-1 inhibition as a precise and effective therapeutic strategy to prevent AKI-to-CKD progression, with early intervention being critical for therapeutic success.},
	doi = {10.1038/s41419-025-08268-7},
	pmid = {41298369 [Indexed for MEDLINE]},
	note = {PMC12824375}
}

@ARTICLE{10.1016/j.phymed.2025.157499,
	author = {Zhang C and Wang H and He Z and He J and Wang F and Yan S and Sheng Y and Yuan N and Chen Y and Xu X and Huang Y and Hu R and Wang M and Xiao W},
	title = {Cinnamic acid prevents skeletal muscle atrophy in nephrectomized rats by modulating apoptosis and endoplasmic reticulum stress.},
	journal = {Phytomedicine},
	year = {2025},
	abstract = {BACKGROUND: Skeletal muscle atrophy is frequently observed in patients with chronic kidney disease (CKD), exacerbating disease progression and diminishing patients' quality of life. Cinnamic acid (CINN), a low-toxicity phenolic acid derived from Cinnamomum cassia (L.) J. Presl, remains uncharacterized in terms of its efficacy and mechanism against CKD-induced skeletal muscle atrophy. PURPOSE: To assess the protective impact of CINN on skeletal muscle atrophy in CKD rats and elucidate its potential molecular mechanisms. METHODS: A 5/6 nephrectomy (5/6 Nx) rat model was constructed and treated with varying concentrations of CINN via gavage. Potential targets and pathways of CINN were identified using network pharmacology and validated through transmission electron microscopy, TUNEL staining, quantitative real-time PCR, and western blot analysis. To confirm whether CINN's therapeutic effects depended on its interaction with the identified target, in vitro experiments employed specific inhibitors to reverse the observed effects. RESULTS: CINN therapy enhanced body and muscle mass, serum albumin concentrations, and various clinical markers. Western blot analysis revealed that CINN inhibited protein proteolysis and promoted protein synthesis in the 5/6 Nx group. Network pharmacology and experimental validation indicated that CINN may alleviate skeletal muscle atrophy by reducing apoptosis and endoplasmic reticulum stress through targeting heat shock protein 90 alpha family class A member 1 (HSP90AA1). In vitro experiments using an HSP90AA1 antagonist demonstrated that the muscle-protective effects of CINN were partially reversed when HSP90AA1 was inhibited. CONCLUSION: CINN may alleviate CKD-induced skeletal muscle atrophy by inhibiting apoptosis and endoplasmic reticulum stress via its action on HSP90AA1.},
	doi = {10.1016/j.phymed.2025.157499},
	pmid = {41206996 [Indexed for MEDLINE]}
}

@ARTICLE{10.1161/CIRCULATIONAHA.125.075579,
	author = {Li X and Raisinghani N and Gallinat A and Santos-Gallego CG and Zhang S and La Salvia S and Yoon S and Yavuz H and Phan A and Shao A and Harding M and Sachs D and Levy CJ and Dogra N and Vasavada R and Dubois NC, Erdbrügger U and Sahoo S},
	title = {Circulating Extracellular Vesicles in the Pathogenesis of Heart Failure in Patients With Chronic Kidney Disease.},
	journal = {Circulation},
	year = {2026},
	abstract = {BACKGROUND: Cardiovascular disease causes >50% of deaths in patients with advanced chronic kidney disease (CKD). Clinical studies suggest that kidney-derived factors contribute to cardiovascular disease development in CKD, independently of comorbidities. However, to date, no kidney-specific humoral risk factor that triggers direct cardiotoxicity has been identified. In this cross-sectional study, we investigate how, in patients with CKD, circulating extracellular vesicles (EVs) facilitate pathological kidney-heart communication, thereby causing cardiotoxicity, impairing cardiac function, and contributing to heart failure progression. METHODS: We investigated the function of EVs from patients with CKD and adenine diet-induced CKD mice on cardiomyocyte and cardiac contractility. microRNA (miRNA) cargo of EVs was identified by small RNA sequencing and quantitative reverse transcription polymerase chain reaction, and their cardiotoxicity was tested by using miRNA mimics. Tissue and cellular origin of CKD-EV-miRNAs were determined from their corresponding primary miRNA expressions in mice. RESULTS: EVs from plasma of patients with CKD, but not from healthy controls, were cardiotoxic; they significantly induced apoptosis both in vitro and in vivo and impaired contractility of adult rat primary cardiomyocytes in vitro. Likewise, EVs from both plasma and kidneys of CKD mice were cardiotoxic. Pharmacologically depleting circulating EVs in CKD mice significantly recovered cardiac function and ameliorated heart failure, improvements that suggest CKD-EVs play a causal role in heart failure pathogenesis. Both human and mouse CKD-EVs were enriched in distinct miRNAs compared with control EVs. CKD-EV-miRNA mimics were cardiotoxic, impairing contractility and downregulating contractile gene expression in human induced pluripotent stem cell-derived cardiomyocytes. It is interesting that levels of endogenous primary miRNAs corresponding to circulating CKD-EV-miRNAs were significantly higher in CKD kidney tissues, specifically in CD45-veCD31-ve renal cells, but not in CKD hearts, CKD livers, or CKD-peripheral blood mononuclear cells, a result that indicates CKD-EV-miRNAs originate renally. It is remarkable that CKD-EV-miRNA levels correlated with established markers of cardiac injury, thus uncovering the presence of subclinical heart disease and demonstrating heterogeneity in reno-cardiac disease. CONCLUSIONS: Collectively, our human subject and mouse studies show that circulating CKD-EVs, carrying distinct renal-derived miRNAs, mediate the molecular crosstalk that contributes to the pathogenesis of heart failure in CKD. Consequently, CKD-EVs hold promise as diagnostic and prognostic biomarkers for early disease detection and as targets for novel therapeutic interventions in chronic reno-cardiac disease.},
	doi = {10.1161/CIRCULATIONAHA.125.075579},
	pmid = {41178538 [Indexed for MEDLINE]},
	note = {PMC12767446}
}

@ARTICLE{10.1080/15548627.2025.2581212,
	author = {Ma T and Yu Y and Luo H and Zhang Z and Wei M and Tian C and Fan X and Yan Z and Zhang S and Hao J and Wang P},
	title = {CircAASS alleviates renal injury and fibrosis by regulating mitochondrial homeostasis in tubular epithelial cells.},
	journal = {Autophagy},
	year = {2026},
	abstract = {Acute kidney injury (AKI) is characterized by the dysfunction of renal tubular epithelial cells (TECs), often leading to renal fibrosis. Mitochondrial impairment is a common hallmark across various types of AKI. However, the potential role of circular RNAs (circRNAs) in modulating mitochondrial homeostasis during AKI and subsequent renal fibrosis remains underexplored. Our findings reveal a significant reduction of circAass levels in the renal cortex across all three AKI models. Mechanistically, circAASS mitigates TEC apoptosis and inflammatory responses by promoting mitochondrial homeostasis, thereby attenuating AKI. Specifically, cytoplasmic circAASS acts as a competing endogenous RNA (ceRNA) by sequestering MIR324-3p, which in turn enhances the expression of PINK1, a critical regulator of mitophagy. Additionally, nuclear circAASS directly interacts with the PPARGC1A/PGC-1α protein, inhibiting its ubiquitin-mediated degradation and thereby promoting mitochondrial biogenesis. Furthermore, we demonstrated that the RNA-binding protein IGF2BP2 suppresses circAASS biogenesis by binding to intronic sequences in the AASS pre-mRNA. Restoring circAass in AKI mouse models improves both mitochondrial biogenesis and mitophagy, ameliorating pro-inflammatory responses of TECs and thus mitigating renal fibrosis. Decreased circAASS expression and its association with impaired mitochondrial function in TECs, followed by more severe renal fibrosis, are observed in AKI patients. Collectively, our results suggest that circAASS protects against AKI by regulating mitochondrial homeostasis, highlighting its potential as a therapeutic target for kidney injury.Abbreviations: AAV9: adeno-associated virus serotype 9; AKI: acute kidney injury; BLAST: Basic Local Alignment Search Tool; ceRNA: competing endogenous RNA; circRNA: circular RNA; CKD: chronic kidney disease; CP-AKI: cisplatin-induced AKI; DHE: dihydroethidium; FISH: fluorescence in situ hybridization; HK2: human renal proximal tubular cells; IF: immunofluorescence; H/R: hypoxia-reoxygenation; I/R: ischemia-reperfusion; ISH: in situ hybridization; LPS: lipopolysaccharide; m6A: N6-methyladenosine; MMP: mitochondrial membrane potential; NC: negative control; ncRNA: non-coding RNA; PAS: periodic acid-schiff staining; PINK1: PTEN induced kinase 1; PRKN: parkin RBR E3 ubiquitin protein ligase; RBPs: RNA-binding proteins; RIP: RNA immunoprecipitation; ROS: reactive oxygen species; RT-qPCR: real-time quantitative polymerase chain reaction; SAKI: septic AKI; Scr: serum creatinine; Seq: sequencing; siRNA: small interfering RNA; TECs: tubular epithelial cells; TEM: transmission electron microscopy.},
	doi = {10.1080/15548627.2025.2581212},
	pmid = {41162865 [Indexed for MEDLINE]},
	note = {PMC12758326}
}
